// Bad: fixed-size chunking
function chunkText(text, size = 500) {
  // Cuts mid-sentence. Loses context.
  return text.match(new RegExp(`.{1,${size}}`, 'g'));
}

// Better: semantic chunking with overlap
function chunkByParagraph(text, { maxTokens = 300, overlap = 50 }) {
  const paragraphs = text.split('\n\n');
  const chunks = [];
  let current = '';

  for (const para of paragraphs) {
    if (tokenCount(current + para) > maxTokens && current) {
      chunks.push(current.trim());
      // Keep last N tokens as overlap
      current = getLastNTokens(current, overlap) + '\n\n' + para;
    } else {
      current += '\n\n' + para;
    }
  }
  if (current.trim()) chunks.push(current.trim());
  return chunks;
}

