async function routeToModel(query) {
  // Simple heuristic routing
  const wordCount = query.split(' ').length;
  const hasCode = /```|function|const |import /.test(query);
  const isComplex = /analyze|compare|explain why|evaluate/.test(query.toLowerCase());

  if (wordCount < 15 && !hasCode && !isComplex) {
    return 'claude-3-5-haiku-20241022';  // Fast, cheap
  } else if (hasCode || isComplex) {
    return 'claude-sonnet-4-20250514';   // Balanced
  } else {
    return 'claude-sonnet-4-20250514';   // Default to Sonnet
  }
}

