async function ragQuery(query) {
  const results = await vectorDB.query({
    vector: await embed(query),
    topK: 5
  });

  // Check if results are actually relevant
  const relevant = results.filter(r => r.score > 0.75);

  if (relevant.length === 0) {
    return {
      answer: 'I don\'t have information about that topic.',
      suggestions: await findRelatedTopics(query),
      source: 'no_results'
    };
  }

  // Only proceed with generation if we have relevant context
  return await generateAnswer(query, relevant);
}

