// Ingestion pipeline
async function ingestDocument(doc) {
  const chunks = chunkDocument(doc);
  for (const chunk of chunks) {
    const embedding = await embed(chunk.text);
    await vectorDB.upsert({
      id: chunk.id,
      values: embedding,
      metadata: { text: chunk.text, source: doc.name }
    });
  }
}

